"""Knowledge atoms for specialized domains (batch 3).

Covers: persistent_homology, diffgeo_ext, diffeq_ext, trigonometry_ext,
sequences_ext, measure_ext, model_theory, category_ext,
convex_optimization, numerical_linalg, numerical_ext2,
actuarial, medical_imaging, cell_biology_ext, geology_ext,
linguistics, linguistics_ext, measurement_ext,
meta_reasoning_ext2, info_theory_ext, info_theory_deep,
nuclear_ext.
"""
from engram_generator.base import Atom
from engram_generator.atoms.registry import register_atom


# ---------------------------------------------------------------------------
# Persistent homology (tier 5-6)
# ---------------------------------------------------------------------------

register_atom(Atom(atom_type="concept", name="simplicial_complex", content="A simplicial complex is a collection of simplices (vertices, edges, triangles, tetrahedra, ...) closed under taking faces. The Rips complex connects points within distance epsilon. Geometric realisation gives a topological space from discrete data.", example="Points {A,B,C} with d(A,B)=1, d(B,C)=1, d(A,C)=2. At epsilon=1.5: edges AB,BC but not AC. Triangle ABC not included.", tier=5, domain="topology", source="Wikipedia contributors, 'Simplicial complex', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Simplicial_complex", prerequisites=[]))

register_atom(Atom(atom_type="algorithm", name="boundary_operator", content="The boundary operator d_n maps n-simplices to (n-1)-chains: d_n([v0,...,vn]) = sum(-1)^i [v0,...,v_hat_i,...,vn]. Key property: d_{n-1} . d_n = 0. This defines a chain complex and homology groups H_n = ker(d_n)/im(d_{n+1}).", example="d_1([A,B]) = [B]-[A]. d_2([A,B,C]) = [B,C]-[A,C]+[A,B]. d_1(d_2([A,B,C])) = (C-B)-(C-A)+(B-A) = 0.", tier=6, domain="topology", source="Wikipedia contributors, 'Simplicial homology', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Simplicial_homology", prerequisites=["simplicial_complex"]))

register_atom(Atom(atom_type="formula", name="betti_from_complex", content="Betti numbers b_k = rank(H_k) count the number of k-dimensional 'holes': b_0 = connected components, b_1 = loops/tunnels, b_2 = voids. Computed as b_k = rank(ker(d_k)) - rank(im(d_{k+1})). Euler characteristic chi = sum(-1)^k * b_k.", example="Torus: b_0=1, b_1=2, b_2=1. chi = 1-2+1 = 0.", tier=6, domain="topology", source="Wikipedia contributors, 'Betti number', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Betti_number", prerequisites=["boundary_operator"]))

register_atom(Atom(atom_type="concept", name="vietoris_rips", content="The Vietoris-Rips complex at scale epsilon includes a simplex [v0,...,vk] iff all pairwise distances d(vi,vj) <= epsilon. Easier to compute than Cech complex. As epsilon varies, simplices appear/disappear, generating a persistence module.", example="3 points: A,B at distance 1, B,C at 1.5, A,C at 2. At epsilon=1: edge AB only. At 1.5: edges AB,BC. At 2: triangle ABC.", tier=6, domain="topology", source="Wikipedia contributors, 'Vietoris-Rips complex', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Vietoris%E2%80%93Rips_complex", prerequisites=["simplicial_complex"]))

register_atom(Atom(atom_type="concept", name="persistence_diagram", content="A persistence diagram plots (birth, death) of topological features across scales. Long-lived features (far from diagonal) represent significant topology; short-lived features are noise. Computed via the persistence algorithm on filtered simplicial complexes.", example="Point cloud forming a circle: H_0 pair born at 0, dies when circle connects. H_1 pair born when loop appears, dies when filled. Loop has large persistence.", tier=6, domain="topology", source="Wikipedia contributors, 'Persistent homology', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Persistent_homology", prerequisites=["vietoris_rips"]))

register_atom(Atom(atom_type="formula", name="bottleneck_distance", content="The bottleneck distance between persistence diagrams P and Q is: d_B(P,Q) = inf_{gamma} sup_x ||x - gamma(x)||_inf, where gamma ranges over bijections (including diagonal points). Measures the maximum discrepancy between matched features. Stability theorem: small perturbations in data give small bottleneck distances.", example="P = {(0,3), (1,2)}. Q = {(0,2.8), (0.9,2.1)}. Optimal matching gives d_B = max(0.2, 0.14) = 0.2.", tier=6, domain="topology", source="Wikipedia contributors, 'Persistent homology', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Persistent_homology#Stability", prerequisites=["persistence_diagram"]))

# ---------------------------------------------------------------------------
# Differential geometry ext (tier 6-7)
# ---------------------------------------------------------------------------

register_atom(Atom(atom_type="formula", name="frenet_serret", content="The Frenet-Serret formulas describe a curve in 3D: T' = kappa*N, N' = -kappa*T + tau*B, B' = -tau*N, where T is tangent, N is normal, B is binormal, kappa is curvature, tau is torsion. They form an orthonormal frame moving along the curve.", example="Helix r(t) = (cos t, sin t, t). T=(-sin t, cos t, 1)/sqrt(2). kappa = 1/2, tau = 1/2. Constant curvature and torsion.", tier=6, domain="differential_geometry", source="Wikipedia contributors, 'Frenet-Serret formulas', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Frenet%E2%80%93Serret_formulas", prerequisites=["cross_product"]))

register_atom(Atom(atom_type="formula", name="surface_normal", content="The surface normal at a point on a parametric surface r(u,v) is n = (r_u x r_v) / |r_u x r_v|, where r_u and r_v are partial derivatives. For an implicit surface F(x,y,z) = 0: n = grad(F) / |grad(F)|.", example="Sphere: F = x^2+y^2+z^2-1. grad F = (2x,2y,2z). At (1,0,0): n = (2,0,0)/2 = (1,0,0).", tier=6, domain="differential_geometry", source="Wikipedia contributors, 'Normal (geometry)', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Normal_(geometry)", prerequisites=["cross_product"]))

register_atom(Atom(atom_type="formula", name="first_fundamental_form", content="The first fundamental form of a surface measures lengths and angles: I = E*du^2 + 2F*du*dv + G*dv^2, where E = r_u.r_u, F = r_u.r_v, G = r_v.r_v. Area element dA = sqrt(EG-F^2) du dv.", example="Sphere r(u,v) = (sin u cos v, sin u sin v, cos u). E=1, F=0, G=sin^2 u. dA = sin u du dv.", tier=6, domain="differential_geometry", source="Wikipedia contributors, 'First fundamental form', Wikipedia.", source_url="https://en.wikipedia.org/wiki/First_fundamental_form", prerequisites=["dot_product"]))

register_atom(Atom(atom_type="formula", name="second_fundamental_form", content="The second fundamental form II = e*du^2 + 2f*du*dv + g*dv^2 measures curvature, where e = r_uu.n, f = r_uv.n, g = r_vv.n. Gaussian curvature K = (eg-f^2)/(EG-F^2). Mean curvature H = (eG-2fF+gE)/(2(EG-F^2)).", example="Sphere of radius R: e=g=1/R, f=0, E=G=R^2, F=0. K = 1/R^2. H = 1/R.", tier=7, domain="differential_geometry", source="Wikipedia contributors, 'Second fundamental form', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Second_fundamental_form", prerequisites=["first_fundamental_form"]))

register_atom(Atom(atom_type="formula", name="mean_curvature", content="Mean curvature H = (kappa_1 + kappa_2)/2, where kappa_1 and kappa_2 are principal curvatures. Minimal surfaces have H = 0 everywhere (soap films). H = (eG - 2fF + gE) / (2(EG-F^2)) from fundamental forms.", example="Cylinder radius R: kappa_1 = 1/R, kappa_2 = 0. H = 1/(2R). Not a minimal surface.", tier=7, domain="differential_geometry", source="Wikipedia contributors, 'Mean curvature', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Mean_curvature", prerequisites=["second_fundamental_form"]))

register_atom(Atom(atom_type="concept", name="parallel_transport", content="Parallel transport moves a vector along a curve while keeping it 'as parallel as possible' (covariant derivative = 0). On a curved surface, parallel transport around a closed loop rotates the vector by the holonomy angle, proportional to the enclosed Gaussian curvature.", example="On a sphere: transport a vector from North Pole along 0-deg meridian to equator, along equator to 90-deg meridian, back to pole. Vector rotates 90 degrees.", tier=7, domain="differential_geometry", source="Wikipedia contributors, 'Parallel transport', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Parallel_transport", prerequisites=["christoffel_symbol"]))

# ---------------------------------------------------------------------------
# Differential equations ext (tier 5-6)
# ---------------------------------------------------------------------------

register_atom(Atom(atom_type="method", name="variation_of_parameters", content="Variation of parameters solves non-homogeneous linear ODEs y'' + p(x)y' + q(x)y = g(x). Given homogeneous solutions y1, y2, the particular solution is y_p = -y1*integral(y2*g/W) + y2*integral(y1*g/W), where W = y1*y2' - y2*y1' is the Wronskian.", example="y'' + y = sec(x). y1=cos x, y2=sin x, W=1. y_p = -cos x * integral(sin x * sec x) + sin x * integral(cos x * sec x) = -cos x * integral(tan x) + sin x * x.", tier=6, domain="differential_equations", source="Wikipedia contributors, 'Variation of parameters', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Variation_of_parameters", prerequisites=["second_derivative"]))

register_atom(Atom(atom_type="method", name="laplace_solve_ode", content="Solving ODEs via Laplace transform: (1) take L{} of both sides, (2) use L{y'} = sY - y(0), L{y''} = s^2Y - sy(0) - y'(0), (3) solve for Y(s), (4) inverse Laplace to get y(t). Handles initial conditions automatically.", example="y' + 2y = 3, y(0) = 1. L: sY - 1 + 2Y = 3/s. Y = (3/s + 1)/(s+2) = 3/(s(s+2)) + 1/(s+2). y(t) = 3/2*(1-e^{-2t}) + e^{-2t} = 3/2 - 1/2*e^{-2t}.", tier=5, domain="differential_equations", source="Wikipedia contributors, 'Laplace transform applied to differential equations', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Laplace_transform_applied_to_differential_equations", prerequisites=["laplace_transform"]))

register_atom(Atom(atom_type="method", name="system_ode_matrix", content="A system of linear ODEs x' = Ax has solution x(t) = exp(At)*x(0). For diagonalisable A = PDP^{-1}: exp(At) = P*diag(exp(lambda_i*t))*P^{-1}. Eigenvalues determine stability: all Re(lambda) < 0 -> asymptotically stable.", example="x'=[[0,1],[-2,-3]]x. Eigenvalues: -1,-2 (both negative -> stable). x(t) = c1*v1*e^{-t} + c2*v2*e^{-2t}.", tier=6, domain="differential_equations", source="Wikipedia contributors, 'Matrix exponential', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Matrix_exponential", prerequisites=["eigenvalue"]))

register_atom(Atom(atom_type="method", name="boundary_value", content="Boundary value problems specify conditions at two points: y(a)=A, y(b)=B. Shooting method: guess y'(a), solve IVP, adjust guess until y(b)=B. Finite difference: discretise domain, solve system of linear equations. Green's function method for linear problems.", example="y'' = -pi^2*y, y(0)=0, y(1)=0. Solution: y = C*sin(pi*x). Boundary conditions determine C.", tier=6, domain="differential_equations", source="Wikipedia contributors, 'Boundary value problem', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Boundary_value_problem", prerequisites=["system_equations"]))

register_atom(Atom(atom_type="concept", name="stability_ode", content="Equilibrium x* of x' = f(x) is stable if nearby solutions stay nearby. Asymptotically stable: solutions converge to x*. Linearisation: x' = Df(x*) * (x - x*). Stable if all eigenvalues of Df have negative real parts. Lyapunov's direct method: find V(x) > 0 with V'(x) < 0.", example="x' = -x^3. Equilibrium x*=0. V=x^2, V' = 2x*(-x^3) = -2x^4 < 0. Asymptotically stable.", tier=6, domain="differential_equations", source="Wikipedia contributors, 'Stability theory', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Stability_theory", prerequisites=["eigenvalue"]))

register_atom(Atom(atom_type="method", name="exact_ode", content="An ODE M(x,y)dx + N(x,y)dy = 0 is exact if dM/dy = dN/dx. Solution: F(x,y) = C where dF/dx = M, dF/dy = N. If not exact, an integrating factor mu may make it exact: mu*M dx + mu*N dy = 0.", example="(2xy+3)dx + (x^2-1)dy = 0. dM/dy = 2x = dN/dx. Exact. F = x^2*y + 3x - y = C.", tier=5, domain="differential_equations", source="Wikipedia contributors, 'Exact differential equation', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Exact_differential_equation", prerequisites=["partial_derivative"]))

# ---------------------------------------------------------------------------
# Trigonometry ext (tier 4-5)
# ---------------------------------------------------------------------------

register_atom(Atom(atom_type="formula", name="inverse_trig", content="Inverse trig functions: arcsin(x) returns angle in [-pi/2, pi/2], arccos(x) in [0, pi], arctan(x) in (-pi/2, pi/2). Derivatives: d/dx arcsin(x) = 1/sqrt(1-x^2), d/dx arctan(x) = 1/(1+x^2).", example="arcsin(0.5) = pi/6 = 30 deg. arccos(0.5) = pi/3 = 60 deg. arctan(1) = pi/4 = 45 deg.", tier=4, domain="trigonometry", source="Wikipedia contributors, 'Inverse trigonometric functions', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Inverse_trigonometric_functions", prerequisites=["sin_cos_eval"]))

register_atom(Atom(atom_type="formula", name="hyperbolic_functions", content="Hyperbolic functions: sinh(x) = (e^x - e^(-x))/2, cosh(x) = (e^x + e^(-x))/2, tanh(x) = sinh(x)/cosh(x). Identity: cosh^2(x) - sinh^2(x) = 1. Derivatives: d/dx sinh(x) = cosh(x), d/dx cosh(x) = sinh(x).", example="sinh(1) = (e-1/e)/2 = (2.718-0.368)/2 = 1.175. cosh(1) = (e+1/e)/2 = 1.543. tanh(1) = 0.762.", tier=5, domain="trigonometry", source="Wikipedia contributors, 'Hyperbolic functions', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Hyperbolic_functions", prerequisites=["exponentiation"]))

register_atom(Atom(atom_type="method", name="trig_equation", content="Solving trigonometric equations: use identities to simplify, then solve for the angle. sin(x)=a: x = arcsin(a) + 2n*pi or pi-arcsin(a) + 2n*pi. cos(x)=a: x = +/-arccos(a) + 2n*pi. tan(x)=a: x = arctan(a) + n*pi.", example="2*sin(x)-1=0 -> sin(x)=0.5 -> x=pi/6 + 2n*pi or 5*pi/6 + 2n*pi.", tier=5, domain="trigonometry", source="Wikipedia contributors, 'Trigonometric equation', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Trigonometric_equation", prerequisites=["inverse_trig"]))

register_atom(Atom(atom_type="formula", name="double_angle", content="Double angle formulas: sin(2x) = 2*sin(x)*cos(x). cos(2x) = cos^2(x) - sin^2(x) = 2*cos^2(x)-1 = 1-2*sin^2(x). tan(2x) = 2*tan(x)/(1-tan^2(x)). Half-angle: sin(x/2) = sqrt((1-cos(x))/2).", example="x = 30 deg. sin(60) = 2*sin(30)*cos(30) = 2*0.5*0.866 = 0.866. cos(60) = 2*cos^2(30)-1 = 2*0.75-1 = 0.5.", tier=4, domain="trigonometry", source="Wikipedia contributors, 'List of trigonometric identities', Wikipedia.", source_url="https://en.wikipedia.org/wiki/List_of_trigonometric_identities#Double-angle_formulae", prerequisites=["sin_cos_eval"]))

register_atom(Atom(atom_type="formula", name="inverse_hyperbolic", content="Inverse hyperbolic functions: arsinh(x) = ln(x + sqrt(x^2+1)), arcosh(x) = ln(x + sqrt(x^2-1)) for x>=1, artanh(x) = 0.5*ln((1+x)/(1-x)) for |x|<1. Used in integration of sqrt(x^2+/-1) forms.", example="arsinh(1) = ln(1+sqrt(2)) = ln(2.414) = 0.881. arcosh(2) = ln(2+sqrt(3)) = ln(3.732) = 1.317.", tier=5, domain="trigonometry", source="Wikipedia contributors, 'Inverse hyperbolic functions', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Inverse_hyperbolic_functions", prerequisites=["hyperbolic_functions"]))

register_atom(Atom(atom_type="method", name="trig_substitution", content="Trigonometric substitution simplifies integrals containing sqrt(a^2-x^2), sqrt(a^2+x^2), or sqrt(x^2-a^2). Substitutions: x=a*sin(t), x=a*tan(t), x=a*sec(t) respectively. Converts to trigonometric integrals.", example="integral sqrt(1-x^2) dx. Let x=sin(t), dx=cos(t)dt. integral cos^2(t)dt = t/2 + sin(2t)/4 + C = arcsin(x)/2 + x*sqrt(1-x^2)/2 + C.", tier=5, domain="trigonometry", source="Wikipedia contributors, 'Trigonometric substitution', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Trigonometric_substitution", prerequisites=["inverse_trig"]))

# ---------------------------------------------------------------------------
# Sequences ext (tier 4-5)
# ---------------------------------------------------------------------------

register_atom(Atom(atom_type="formula", name="harmonic_series", content="The harmonic series sum(1/n) from n=1 to infinity diverges. Partial sums H_n = 1 + 1/2 + 1/3 + ... + 1/n ~ ln(n) + gamma, where gamma = 0.5772... is the Euler-Mascheroni constant. The alternating harmonic series sum((-1)^(n+1)/n) = ln(2).", example="H_10 = 1+0.5+0.333+0.25+0.2+0.167+0.143+0.125+0.111+0.1 = 2.929. ln(10)+0.577 = 2.880.", tier=4, domain="sequences", source="Wikipedia contributors, 'Harmonic series (mathematics)', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Harmonic_series_(mathematics)", prerequisites=["summation"]))

register_atom(Atom(atom_type="formula", name="telescoping_series", content="A telescoping series has partial sums that simplify by cancellation: sum(a_n - a_{n+1}) = a_1 - lim a_n. Example: sum(1/(n(n+1))) = sum(1/n - 1/(n+1)) = 1 - lim 1/(n+1) = 1.", example="sum_{n=1}^{N} 1/(n(n+1)) = 1 - 1/(N+1). As N->inf: sum = 1.", tier=4, domain="sequences", source="Wikipedia contributors, 'Telescoping series', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Telescoping_series", prerequisites=["partial_fractions"]))

register_atom(Atom(atom_type="formula", name="recurrence_second_order", content="A second-order linear recurrence a_n = p*a_{n-1} + q*a_{n-2} has solution a_n = A*r1^n + B*r2^n, where r1,r2 are roots of x^2 - px - q = 0. If r1=r2: a_n = (A+Bn)*r^n. Fibonacci: a_n = a_{n-1}+a_{n-2}, roots (1+/-sqrt(5))/2.", example="a_n = 3*a_{n-1} - 2*a_{n-2}, a_0=1, a_1=3. Char eq: x^2-3x+2=0, roots 1,2. a_n = -1*1^n + 2*2^n = 2^{n+1}-1.", tier=5, domain="sequences", source="Wikipedia contributors, 'Recurrence relation', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Recurrence_relation#Solving_linear_recurrence_relations", prerequisites=["quadratic"]))

register_atom(Atom(atom_type="formula", name="power_series_eval", content="A power series sum(a_n * x^n) converges within radius R = 1/limsup|a_n|^(1/n) (root test) or R = lim|a_n/a_{n+1}| (ratio test). Common: e^x = sum x^n/n!, sin x = sum (-1)^n x^{2n+1}/(2n+1)!, 1/(1-x) = sum x^n for |x|<1.", example="e^1 = sum 1/n! = 1+1+0.5+0.167+0.042+... = 2.718. Converges for all x (R=inf).", tier=5, domain="sequences", source="Wikipedia contributors, 'Power series', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Power_series", prerequisites=["taylor_series"]))

register_atom(Atom(atom_type="formula", name="sequence_limit", content="A sequence {a_n} converges to L if for every epsilon>0, there exists N such that |a_n - L| < epsilon for all n > N. Common limits: lim (1+1/n)^n = e, lim n^{1/n} = 1, lim x^n = 0 for |x|<1.", example="a_n = (3n+1)/(2n+5). lim = 3/2 (ratio of leading coefficients). For epsilon=0.01, need |a_n-1.5|<0.01 -> n > 345.", tier=4, domain="sequences", source="Wikipedia contributors, 'Limit of a sequence', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Limit_of_a_sequence", prerequisites=["limit"]))

register_atom(Atom(atom_type="formula", name="fibonacci_properties", content="Fibonacci properties: F(n) ~ phi^n/sqrt(5) (Binet). Cassini's identity: F(n-1)*F(n+1) - F(n)^2 = (-1)^n. Addition formula: F(m+n) = F(m)*F(n+1) + F(m-1)*F(n). GCD property: gcd(F(m),F(n)) = F(gcd(m,n)). Pisano period: F(n) mod m is periodic.", example="F(10)=55. Binet: phi^10/sqrt(5) = 122.99/2.236 = 55.0. Cassini: F(9)*F(11)-F(10)^2 = 34*89-3025 = 3026-3025 = 1 = (-1)^10.", tier=5, domain="sequences", source="Wikipedia contributors, 'Fibonacci number', Wikipedia.", source_url="https://en.wikipedia.org/wiki/Fibonacci_number#Identities", prerequisites=["fibonacci"]))

